    </div>
    <div>
      <label for="itemName">Item Name</label>
      <input id="itemName" [(ngModel)]="form.name" type="text">
    </div>
    <div>
      <label for="itemCategory">Category</label>
      <select id="itemCategory" [(ngModel)]="form.category">
        <option *ngFor="let category of categories" [ngValue]="category">{{ category }}</option>
      </select>
    </div>
    <div>
      <label for="itemQuantity">Quantity</label>
      <input id="itemQuantity" [(ngModel)]="form.quantity" type="number" min="0" step="1">
    </div>
    <div>
      <label for="itemPrice">Price</label>
      <input id="itemPrice" [(ngModel)]="form.price" type="number" min="0" step="0.01">
    </div>
    <div>
      <label for="supplier">Supplier</label>
      <input id="supplier" [(ngModel)]="form.supplier" type="text">
    </div>
    <div>
      <label for="stockStatus">Stock Status</label>
      <select id="stockStatus" [(ngModel)]="form.stockStatus">
        <option *ngFor="let status of stockStatuses" [ngValue]="status">{{ status }}</option>
      </select>
    </div>
    <div>
      <label for="popular">Popular Item</label>
      <select id="popular" [(ngModel)]="form.popular">
        <option [ngValue]="true">Yes</option>
        <option [ngValue]="false">No</option>
      </select>
    </div>
    <div style="grid-column: 1 / -1;">
      <label for="comment">Comment (Optional)</label>
      <textarea id="comment" [(ngModel)]="form.comment" rows="3"></textarea>
    </div>
  </div>

  <div class="row">
    <button type="button" (click)="addItem()">Add Item</button>
    <button type="button" (click)="loadByName()" class="secondary">Load by Name</button>
    <button type="button" (click)="updateItemByName()">Update by Name</button>
    <button type="button" (click)="requestDelete()" class="danger">Delete by Name</button>
  </div>

  <div class="row" *ngIf="pendingDelete">
    <button type="button" (click)="confirmDelete()" class="danger">Confirm Delete</button>
    <button type="button" (click)="cancelDelete()" class="secondary">Cancel</button>
  </div>

  <div class="message" [ngClass]="{ success: messageType === 'success', error: messageType === 'error' }">
    {{ message || 'Use this page to maintain inventory records.' }}
  </div>

  <table>
    <thead>
      <tr>
        <th>ID</th>
        <th>Name</th>
        <th>Category</th>
        <th>Qty</th>
        <th>Price</th>
        <th>Supplier</th>
        <th>Stock</th>
        <th>Popular</th>
      </tr>
    </thead>
    <tbody>
      <tr *ngFor="let item of items">
        <td>{{ item.id }}</td>
        <td>{{ item.name }}</td>
        <td>{{ item.category }}</td>
        <td>{{ item.quantity }}</td>
        <td>{{ item.price | number: '1.2-2' }}</td>
        <td>{{ item.supplier }}</td>
        <td>{{ item.stockStatus }}</td>
        <td>{{ item.popular ? 'Yes' : 'No' }}</td>
      </tr>
    </tbody>
  </table>
</section>
